205→// VectorSelector represents a Vector selection.
206→type VectorSelector struct {
207→	Name string
208→	// OriginalOffset is the actual offset calculated from OriginalOffsetExpr.
209→	OriginalOffset time.Duration
210→	// OriginalOffsetExpr is the actual offset that was set in the query.
211→	OriginalOffsetExpr *DurationExpr
212→	// Offset is the offset used during the query execution
213→	// which is calculated using the original offset, at modifier time,
214→	// eval time, and subquery offsets in the AST tree.
215→	Offset               time.Duration
216→	Timestamp            *int64
217→	SkipHistogramBuckets bool     // Set when decoding native histogram buckets is not needed for query evaluation.
218→	StartOrEnd           ItemType // Set when @ is used with start() or end()
219→	LabelMatchers        []*labels.Matcher
220→
221→	// The unexpanded seriesSet populated at query preparation time.
222→	UnexpandedSeriesSet storage.SeriesSet
223→	Series              []storage.Series
224→
225→	// BypassEmptyMatcherCheck is true when the VectorSelector isn't required to have at least one matcher matching the empty string.
226→	// This is the case when VectorSelector is used to represent the info function's second argument.
227→	BypassEmptyMatcherCheck bool
228→
229→	// Anchored is true when the VectorSelector is anchored.
230→	Anchored bool
231→	// Smoothed is true when the VectorSelector is smoothed.
232→	Smoothed bool
233→
234→	PosRange posrange.PositionRange
235→}
