237→// TestStmt is an internal helper statement that allows execution
238→// of an arbitrary function during handling. It is used to test the Engine.
239→type TestStmt func(context.Context) error
240→
241→func (TestStmt) String() string      { return "test statement" }
242→func (TestStmt) PromQLStmt()         {}
243→func (t TestStmt) Pretty(int) string { return t.String() }
244→
245→func (TestStmt) PositionRange() posrange.PositionRange {
246→	return posrange.PositionRange{
247→		Start: -1,
248→		End:   -1,
249→	}
