103→// MarshalJSON implements json.Marshaler.
104→//
105→// JSON marshaling is only needed for the HTTP API. Since FPoint is such a
106→// frequently marshaled type, it gets an optimized treatment directly in
107→// web/api/v1/api.go. Therefore, this method is unused within Prometheus. It is
108→// still provided here as convenience for debugging and for other users of this
109→// code. Also note that the different marshaling implementations might lead to
110→// slightly different results in terms of formatting and rounding of the
111→// timestamp.
112→func (p FPoint) MarshalJSON() ([]byte, error) {
113→	v := strconv.FormatFloat(p.F, 'f', -1, 64)
114→	return json.Marshal([...]any{float64(p.T) / 1000, v})
