128→// MarshalJSON implements json.Marshaler.
129→//
130→// JSON marshaling is only needed for the HTTP API. Since HPoint is such a
131→// frequently marshaled type, it gets an optimized treatment directly in
132→// web/api/v1/api.go. Therefore, this method is unused within Prometheus. It is
133→// still provided here as convenience for debugging and for other users of this
134→// code. Also note that the different marshaling implementations might lead to
135→// slightly different results in terms of formatting and rounding of the
136→// timestamp.
137→func (p HPoint) MarshalJSON() ([]byte, error) {
138→	h := struct {
139→		Count   string  `json:"count"`
140→		Sum     string  `json:"sum"`
141→		Buckets [][]any `json:"buckets,omitempty"`
142→	}{
143→		Count: strconv.FormatFloat(p.H.Count, 'f', -1, 64),
144→		Sum:   strconv.FormatFloat(p.H.Sum, 'f', -1, 64),
145→	}
146→	it := p.H.AllBucketIterator()
147→	for it.Next() {
148→		bucket := it.At()
149→		if bucket.Count == 0 {
150→			continue // No need to expose empty buckets in JSON.
151→		}
152→		boundaries := 2 // Exclusive on both sides AKA open interval.
153→		if bucket.LowerInclusive {
154→			if bucket.UpperInclusive {
155→				boundaries = 3 // Inclusive on both sides AKA closed interval.
156→			} else {
157→				boundaries = 1 // Inclusive only on lower end AKA right open.
158→			}
159→		} else {
160→			if bucket.UpperInclusive {
161→				boundaries = 0 // Inclusive only on upper end AKA left open.
162→			}
163→		}
164→		bucketToMarshal := []any{
165→			boundaries,
166→			strconv.FormatFloat(bucket.Lower, 'f', -1, 64),
167→			strconv.FormatFloat(bucket.Upper, 'f', -1, 64),
168→			strconv.FormatFloat(bucket.Count, 'f', -1, 64),
169→		}
170→		h.Buckets = append(h.Buckets, bucketToMarshal)
171→	}
172→	return json.Marshal([...]any{float64(p.T) / 1000, h})
173→}
