455→func (ssi *storageSeriesIterator) Seek(t int64) chunkenc.ValueType {
456→	if ssi.iFloats >= len(ssi.floats) && ssi.iHistograms >= len(ssi.histograms) {
457→		return chunkenc.ValNone
458→	}
459→	for ssi.currT < t {
460→		if ssi.Next() == chunkenc.ValNone {
461→			return chunkenc.ValNone
462→		}
463→	}
464→	if ssi.currH != nil {
465→		return chunkenc.ValFloatHistogram
466→	}
467→	return chunkenc.ValFloat
