495→func (ssi *storageSeriesIterator) Next() chunkenc.ValueType {
496→	if ssi.currH != nil {
497→		ssi.iHistograms++
498→	} else {
499→		ssi.iFloats++
500→	}
501→	var (
502→		pickH, pickF        = false, false
503→		floatsExhausted     = ssi.iFloats >= len(ssi.floats)
504→		histogramsExhausted = ssi.iHistograms >= len(ssi.histograms)
505→	)
506→
507→	switch {
508→	case floatsExhausted:
509→		if histogramsExhausted { // Both exhausted!
510→			return chunkenc.ValNone
511→		}
512→		pickH = true
513→	case histogramsExhausted: // and floats not exhausted.
514→		pickF = true
515→	// From here on, we have to look at timestamps.
516→	case ssi.histograms[ssi.iHistograms].T < ssi.floats[ssi.iFloats].T:
517→		// Next histogram comes before next float.
518→		pickH = true
519→	default:
520→		// In all other cases, we pick float so that we first iterate
521→		// through floats if the timestamp is the same.
522→		pickF = true
523→	}
524→
525→	switch {
526→	case pickF:
527→		p := ssi.floats[ssi.iFloats]
528→		ssi.currT = p.T
529→		ssi.currF = p.F
530→		ssi.currH = nil
531→		return chunkenc.ValFloat
532→	case pickH:
533→		p := ssi.histograms[ssi.iHistograms]
534→		ssi.currT = p.T
535→		ssi.currF = 0
536→		ssi.currH = p.H
537→		return chunkenc.ValFloatHistogram
538→	default:
539→		panic("storageSeriesIterator.Next failed to pick value type")
540→	}
541→}
