547→type fParams struct {
548→	series     Series
549→	constValue float64
550→	isConstant bool
551→	minValue   float64
552→	maxValue   float64
553→	hasAnyNaN  bool
554→}
555→
556→// newFParams evaluates the expression and returns an fParams object,
557→// which holds the parameter values (constant or series) along with min, max, and NaN info.
558→func newFParams(ctx context.Context, ev *evaluator, expr parser.Expr) (*fParams, annotations.Annotations) {
559→	if expr == nil {
560→		return &fParams{}, nil
561→	}
562→	var constParam bool
563→	if _, ok := expr.(*parser.NumberLiteral); ok {
564→		constParam = true
565→	}
566→	val, ws := ev.eval(ctx, expr)
567→	mat, ok := val.(Matrix)
568→	if !ok || len(mat) == 0 {
569→		return &fParams{}, ws
570→	}
571→	fp := &fParams{
572→		series:     mat[0],
573→		isConstant: constParam,
574→		minValue:   math.MaxFloat64,
575→		maxValue:   -math.MaxFloat64,
576→	}
577→
578→	if constParam {
579→		fp.constValue = fp.series.Floats[0].F
580→		fp.minValue, fp.maxValue = fp.constValue, fp.constValue
581→		fp.hasAnyNaN = math.IsNaN(fp.constValue)
582→		return fp, ws
583→	}
584→
585→	for _, v := range fp.series.Floats {
586→		fp.maxValue = math.Max(fp.maxValue, v.F)
587→		fp.minValue = math.Min(fp.minValue, v.F)
588→		if math.IsNaN(v.F) {
589→			fp.hasAnyNaN = true
590→		}
591→	}
592→	return fp, ws
593→}
594→
595→func (fp *fParams) Max() float64    { return fp.maxValue }
596→func (fp *fParams) Min() float64    { return fp.minValue }
597→func (fp *fParams) HasAnyNaN() bool { return fp.hasAnyNaN }
598→
599→// Next returns the next value from the series or the constant value, and advances the series if applicable.
600→func (fp *fParams) Next() float64 {
601→	if fp.isConstant {
602→		return fp.constValue
603→	}
604→	if len(fp.series.Floats) > 0 {
605→		val := fp.series.Floats[0].F
606→		fp.series.Floats = fp.series.Floats[1:]
607→		return val
608→	}
609→	return 0
610→}
